/**
 * SpaceOS 9거점 PPPP 데이터 모듈 (React 범용 컴포넌트 DistrictPPPP 용).
 * 멀티거점 통합본(SpaceOS_Goyang_MultiDistrict_PPPP.html)의 DISTRICTS를 타입 안전 이식.
 * 좌표는 네이버 지도 기준 역·랜드마크 정합. 거점별 6 감성구역·5 공실유닛·3 행사.
 * TODO: 실데이터 연동 시 거점별 API(/api/v1/commercial-districts/{id}/...)로 대체.
 */

export type PKey = "P1" | "P2" | "P3" | "P4";
export type TierKey = "premium" | "value" | "factory";

export interface Zone { id: string; n: string; grp: string; lat: number; lng: number; s: number; d: number; r: number; f: [string, string, "up" | "dn"][]; }
export interface Cell { i: number; j: number; lat: number; lng: number; cLat: number; cLng: number; v: number; stores: number; vacN: number; dlat: number; dlng: number; }
export interface Unit { id: string; n: string; grp: string; lat: number; lng: number; area: number; rent: number; prem: number; floor: string; was: string; rec: TierKey; foot: "저" | "중" | "고"; persona: string; note: string; }
export interface EventItem { id: string; n: string; lat: number; lng: number; ic: string; when: string; k2: string; desc: string; roles: string[]; ha: string; }
export interface Grid { bb: { s: number; n: number; w: number; e: number }; dlat: number; dlng: number; core: [number, number]; maxd: number; hot: [number, number, number, number][]; }
export type PoI = [number, number, string, string]; // lat,lng,label,cls
export interface District { id: string; name: string; sub: string; center: [number, number]; zoom: number; poi: PoI[]; zones: Zone[]; grid: Grid; units: Unit[]; events: EventItem[]; insta: string[]; }

/* ===== 헬퍼 ===== */
export const fgHex = (s: number) => (s < 40 ? "#d9716a" : s < 60 ? "#e3b95e" : s < 80 ? "#7faa55" : "#3a5a98");
export const fgV = (s: number) => (s < 40 ? "#b23b39" : s < 60 ? "#9a7b1e" : s < 80 ? "#4f7a31" : "#3a5a98");
export const vacColor = (v: number) => (v < 5 ? "#cfe3cf" : v < 10 ? "#fbe7a6" : v < 18 ? "#f6b96b" : v < 28 ? "#e8743b" : "#c0392b");
export const arrow = (d: number) => (d > 0 ? "↑" + d.toFixed(1) : d < 0 ? "↓" + Math.abs(d).toFixed(1) : "→" + d.toFixed(1));
export const rev = (n: number) => (n >= 1000 ? (n / 1000).toFixed(1) + "K" : String(n));
export const rad = (r: number) => 12 + Math.sqrt(r) / 3;
export const TIER: Record<TierKey, { nm: string; sub: string; c: string; bg: string }> = {
  premium: { nm: "고급화", sub: "Premium", c: "#7a4f9a", bg: "#efe7f5" },
  value: { nm: "가성비", sub: "Value", c: "#2f7d4f", bg: "#e0f0e6" },
  factory: { nm: "공장제", sub: "Standardized", c: "#b06a1e", bg: "#f6e9d4" },
};
export const mixHi: [string, number, string][] = [["요식", 24, "#e8743b"], ["공실", 38, "#c0392b"], ["생활편의", 14, "#9aa3af"], ["뷰티", 8, "#c98bbf"], ["기타", 16, "#cbd2d9"]];
export const mixMid: [string, number, string][] = [["요식", 32, "#e8743b"], ["공실", 17, "#c0392b"], ["생활편의", 16, "#9aa3af"], ["카페", 13, "#b07a4a"], ["뷰티", 10, "#c98bbf"], ["기타", 12, "#cbd2d9"]];
export const mixLo: [string, number, string][] = [["요식", 40, "#e8743b"], ["카페", 20, "#b07a4a"], ["패션", 14, "#7a9ad6"], ["뷰티", 10, "#c98bbf"], ["공실", 6, "#c0392b"], ["기타", 10, "#cbd2d9"]];
export const mixFor = (v: number) => (v >= 24 ? mixHi : v >= 10 ? mixMid : mixLo);

export interface Scenario { invest: number; monthCost: number; monthRev: number; }
export function scenarios(u: Unit): Record<TierKey, Scenario> {
  const fK = { 저: 0.8, 중: 1.0, 고: 1.25 }[u.foot], base = u.area * fK;
  return {
    premium: { invest: Math.round(u.prem / 100 + u.area * 0.55 + 4), monthCost: Math.round(u.rent + u.area * 1.8 + 180), monthRev: Math.round(base * 41 + 1150) },
    value: { invest: Math.round(u.prem / 100 + u.area * 0.32 + 2.2), monthCost: Math.round(u.rent + u.area * 1.1 + 95), monthRev: Math.round(base * 30 + 760) },
    factory: { invest: Math.round(u.prem / 100 + u.area * 0.2 + 1.1), monthCost: Math.round(u.rent + u.area * 0.45 + 25), monthRev: Math.round(base * 18 + 430) },
  };
}
export const roiM = (s: Scenario) => { const net = s.monthRev - s.monthCost; return net <= 0 ? 99 : s.invest / net; };

const distM = (a: number, b: number, c: number, d: number) => { const dy = (a - c) * 111000, dx = (b - d) * 88300; return Math.sqrt(dx * dx + dy * dy); };
const seed = (i: number, j: number) => { const x = Math.sin(i * 12.9898 + j * 78.233) * 43758.5453; return x - Math.floor(x); };
export function buildCells(g: Grid): { cells: Cell[]; sumStores: number; sumVac: number } {
  const cells: Cell[] = []; let sumStores = 0, sumVac = 0;
  for (let lat = g.bb.s, i = 0; lat < g.bb.n - 1e-9; lat += g.dlat, i++) {
    for (let lng = g.bb.w, j = 0; lng < g.bb.e - 1e-9; lng += g.dlng, j++) {
      const cLat = lat + g.dlat / 2, cLng = lng + g.dlng / 2;
      let v = 2.5, infl = 0;
      g.hot.forEach((h) => { const dd = distM(cLat, cLng, h[0], h[1]), w = Math.exp(-(dd * dd) / (2 * h[2] * h[2])); v += h[3] * w; infl += w; });
      v += (seed(i, j) - 0.5) * 4;
      const dc = distM(cLat, cLng, g.core[0], g.core[1]);
      if (!(infl > 0.12 && dc < g.maxd)) continue;
      v = Math.max(2, Math.min(48, v));
      const stores = Math.round(8 + 22 * Math.min(1, infl) + seed(j, i) * 10), vacN = Math.round((stores * v) / 100);
      cells.push({ i, j, lat, lng, cLat, cLng, v, stores, vacN, dlat: g.dlat, dlng: g.dlng });
      sumStores += stores; sumVac += vacN;
    }
  }
  return { cells, sumStores, sumVac };
}

/* 데이터 생성 헬퍼 (가독성) */
const Z = (a: [string, string, string, number, number, number, number, number, [string, string, "up" | "dn"][]]): Zone => ({ id: a[0], n: a[1], grp: a[2], lat: a[3], lng: a[4], s: a[5], d: a[6], r: a[7], f: a[8] });
const U = (a: [string, string, string, number, number, number, number, number, string, string, TierKey, "저" | "중" | "고", string, string]): Unit => ({ id: a[0], n: a[1], grp: a[2], lat: a[3], lng: a[4], area: a[5], rent: a[6], prem: a[7], floor: a[8], was: a[9], rec: a[10], foot: a[11], persona: a[12], note: a[13] });
const E = (a: [string, string, number, number, string, string, string, string, string[], string]): EventItem => ({ id: a[0], n: a[1], lat: a[2], lng: a[3], ic: a[4], when: a[5], k2: a[6], desc: a[7], roles: a[8], ha: a[9] });

